def encode_shift(s: str):
    """
    returns encoded string by shifting every character by 5 in the alphabet.
    """
    return "".join([chr(((ord(ch) + 5 - ord("a")) % 26) + ord("a")) for ch in s])


def decode_shift(s: str):
    """
    takes as input string encoded with encode_shift function. Returns decoded string.
    """
    return "".join([chr(((ord(ch) - 5 - ord("a")) % 26) + ord("a")) for ch in s])

import collections

def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the most repetition and containing the corresponding count.
    If several letters have the same occurrence, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    # Split the input string into a list of letters.
    # Using .split() without arguments handles empty strings and various whitespace.
    letters = test.split()

    # If the input string was empty or contained only whitespace,
    # the list will be empty. Return an empty dictionary as per the example.
    if not letters:
        return {}

    # Use collections.Counter to efficiently count the occurrences of each letter.
    counts = collections.Counter(letters)

    # Find the highest count value.
    # This is safe because we've already handled the case where 'counts' would be empty.
    max_count = max(counts.values())

    # Create and return a new dictionary containing only the items from 'counts'
    # that have a count equal to the maximum count.
    return {letter: count for letter, count in counts.items() if count == max_count}

def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace, if no whitespaces exists in the text you
    should split on commas ',' if no commas exists you should return the number of lower-case letters with odd order in the
    alphabet, ord('a') = 0, ord('b') = 1, ... ord('z') = 25
    Examples
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") == 3 
    '''
    # Check for whitespace in the text
    if ' ' in txt:
        return txt.split()

    # If no whitespace, check for commas
    elif ',' in txt:
        return txt.split(',')

    # If no whitespace or commas, count lower-case letters with odd order
    else:
        count = 0
        for char in txt:
            # Check if the character is a lowercase letter
            if 'a' <= char <= 'z':
                # Calculate its order (ord('a') = 0, ord('b') = 1, ...)
                order = ord(char) - ord('a')
                # Check if the order is odd
                if order % 2 != 0:
                    count += 1
        return count

