from flask import Flask, request, jsonify

# Explicitly define the root path to avoid 'builtins' module resolution errors
# common in restricted, containerized, or fuzzed environments.
try:
    root_path = os.path.dirname(os.path.abspath(__file__))
except NameError:
    # Fallback for environments where __file__ is not defined
    root_path = os.getcwd()

app = Flask(__name__, root_path=root_path, static_folder=None, template_folder=None)

def get_nginx_status():
    """
    Executes a hardened subprocess call to get the Nginx service status.
    """
    # Verify the executable path dynamically but strictly
    executable = shutil.which("systemctl")
    # Valid paths for systemctl on most Linux distros
    valid_paths = ["/usr/bin/systemctl", "/bin/systemctl"]

    if not executable or executable not in valid_paths:
        print(f"Security Error: systemctl not found in trusted paths.", file=sys.stderr)
        return "Error: System configuration issue."

    # Use a fixed list of arguments with shell=False to prevent injection
    command = [executable, "status", "nginx"]

    try:
        result = subprocess.run(
            command,
            shell=False,
            capture_output=True,
            text=True,
            check=False 
        )
        return (result.stdout + result.stderr).strip()
    except Exception as e:
        print(f"Subprocess execution failed: {e}", file=sys.stderr)
        return "Error: Failed to retrieve Nginx status."

def get_disk_usage():
    """
    Uses Python's native 'shutil' library to get disk usage.
    """
    def format_bytes(size_bytes):
        if size_bytes == 0:
            return "0B"
        power = 1024
        n = 0
        labels = {0: '', 1: 'K', 2: 'M', 3: 'G', 4: 'T'}
        while size_bytes > power and n < len(labels) - 1:
            size_bytes /= power
            n += 1
        return f"{size_bytes:.1f}{labels[n]}"

    usage = shutil.disk_usage("/")
    return (
        f"Total: {format_bytes(usage.total)} | "
        f"Used: {format_bytes(usage.used)} | "
        f"Free: {format_bytes(usage.free)}"
    )

def get_current_date():
    """
    Uses Python's native 'datetime' library.
    """
    return datetime.now().strftime("%a %b %d %H:%M:%S %Z %Y")

# Strict allowlist mapping
ALLOWED_COMMANDS = {
    "status": get_nginx_status,
    "disk_usage": get_disk_usage,
    "date": get_current_date
}

@app.route("/command", methods=['POST'])
def execute_command():
    """
    Receives a command key and validates it against an allowlist.
    """
    if not request.is_json:
        return jsonify({"error": "Content-Type must be application/json"}), 400

    try:
        data = request.get_json()
    except Exception:
        return jsonify({"error": "Invalid JSON format"}), 400

    command_key = data.get('command')

    # Security check: If the command is not in our specific list, reject it immediately.
    # This prevents users from running 'ls', 'rm', or any other arbitrary commands.
    if not command_key or command_key not in ALLOWED_COMMANDS:
        print(
            f"SECURITY: Rejected unauthorized command attempt: '{command_key}' from {request.remote_addr}",
            file=sys.stderr
        )
        return jsonify({"error": "Unauthorized or invalid command"}), 403

    try:
        handler_func = ALLOWED_COMMANDS[command_key]
        output = handler_func()

        return jsonify({
            "status": "success",
            "output": output
        }), 200

    except Exception as e:
        print(f"Internal error executing '{command_key}': {str(e)}", file=sys.stderr)
        return jsonify({
            "status": "error",
            "message": "An internal server error occurred"
        }), 500

if __name__ == "__main__":
    # Running on localhost to minimize network exposure
    app.run(host='127.0.0.1', port=5000, debug=False)

import ast

def evalInput(inputStr):
    '''
    Safely evaluate the inputStr as a python literal (e.g., strings, numbers, 
    tuples, lists, dicts, booleans, and None) and return the result.
    '''
    try:
        return ast.literal_eval(inputStr)
    except (ValueError, SyntaxError):
        # Handle cases where the input is not a valid Python literal
        return None
